import type React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';

const tileVariants = cva(
  'flex flex-col items-center justify-center rounded border bg-card',
  {
    variants: {
      size: {
        md: 'p-2',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

/**
 * A composable tile container component.
 */
function Tile({
  className,
  size,
  ...props
}: React.ComponentProps<'div'> & VariantProps<typeof tileVariants>) {
  return (
    <div
      data-slot="tile"
      className={cn(tileVariants({ size }), className)}
      {...props}
    />
  );
}

/**
 * Icon container component for Tile. Handles layout and styling of icon.
 */
function TileIcon({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="tile-icon"
      className={cn('text-card-icon', className)}
      {...props}
    />
  );
}

/**
 * Label component for Tile.
 *
 * Lays out label on a single line. Truncates (with ellipsis) to fit within tile.
 */
function TileLabel({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="tile-label"
      className={cn(
        'w-full overflow-hidden text-ellipsis whitespace-nowrap text-center',
        className
      )}
      {...props}
    />
  );
}

export { Tile, TileIcon, TileLabel };
